expected_solidity:
function getTransactionIds(uint from, uint to, bool pending, bool executed) public view returns (uint[] memory _transactionIds) {
        uint[] memory transactionIdsTemp = new uint[](transactionCount);
        uint count = 0;
        uint i;
        for (i=0; i<transactionCount; i++)
            if (   pending && !transactions[i].executed
                || executed && transactions[i].executed)
            {
                transactionIdsTemp[count] = i;
                count += 1;
            }
        _transactionIds = new uint[](to - from);
        for (i=from; i<to; i++)
            _transactionIds[i - from] = transactionIdsTemp[i];
        return _transactionIds;
    }

model_output:
function getTransactionIds(uint256 fromBlock, uint256 toBlock, bool fromFirst, bool toFirst) public view returns (uint256[] memory) {
        uint256[] memory ids = new uint256[](toBlock - fromBlock);
        uint256 index = 0;
        for (uint256 i = fromBlock; i < toBlock; i++) {
            if (fromFirst) {
                ids[index] = i;
                index++;
            }
            if (toFirst) {
                ids[index] = i;
                index++;
            }
        }
        return ids;
    }

