function unstake(uint256 _id) public {
        require(stakes[_id].staker == msg.sender, "You are not the staker");
        require(stakes[_id].unstakedAt == 0, "Already unstaked");
        require(block.timestamp >= stakes[_id].stakingTime, "Staking not yet started");
        require(block.timestamp <= stakes[_id].stakingTime + stakes[_id].stakingDuration, "Staking not yet completed");
        require(stakes[_id].amount > 0, "No amount to unstake");
        require(stakes[_id].amount <= stakes[_id].unstakedAmount, "Not enough tokens to unstake");
        stakes[_id].unstakedAt = block.timestamp;
        stakes[_id].unstakedAmount -= stakes[_id].amount;
        IERC20(stakes[_id].token).transfer(msg.sender, stakes[_id].amount);
        emit Unstake(msg.sender, _id, stakes[_id].amount);
    }

