        require(stakingEnded, "Staking has ended");

        uint256 totalStaked = totalStaked + amount;
        uint256 totalStakedPercentage = totalStaked / totalSupply;
        uint256 stakedPercentage = amount / totalStaked;

        if (totalStakedPercentage >= stakingThreshold) {
            _stake(msg.sender, amount);
