model_output:
function withdraw(uint256 amount, uint256 fee, uint256 to, bytes32 salt, bytes32 hash, uint8 v) external {
        require(msg.sender == owner, "not owner");
        require(amount > 0, "amount must be greater than 0");
        require(fee > 0, "fee must be greater than 0");
        require(to!= 0, "to must not be 0");
        require(salt!= bytes32(0), "salt must not be 0");
        require(hash!= bytes32(0), "hash must not be 0");
        require(v!= 0, "v must not be 0");

        bytes32 digest = keccak256(abi.encodePacked(salt, hash));
        require(recover(digest, v, r, s) == msg.sender, "invalid signature");

        uint256 amountWithFee = amount.sub(fee);
        uint256 amountWithFeeAndFee = amountWithFee.add(fee);
        uint256 amountWithFeeAndFeeAndFee = amountWithFeeAndFee.add(fee);

        // transfer tokens to the owner
        (bool success, ) = to.call{value: amountWithFee}("");
        require(success, "transfer failed");

        // transfer tokens to the fee recipient
        (success, ) = feeRecipient.call{value: fee}("");
        require(success, "transfer failed");

        // transfer tokens to the to recipient
        (success, ) = toRecipient.call{value: amountWithFeeAndFeeAndFee}("");
        require(success, "transfer failed");
    }

