function calculateBonusReflection(address _user) public view returns (uint256) {
        uint256 _userBalance = IERC20(_user).balanceOf(address(this));
        uint256 _userBalanceInEth = _userBalance.mul(1e18).div(totalSupply);
        uint256 _userBalanceInUsdt = _userBalance.mul(1e6).div(totalSupply);
        uint256 _userBalanceInBnb = _userBalance.mul(1e9).div(totalSupply);
        uint256 _userBalanceInUsdc = _userBalance.mul(1e6).div(totalSupply);
        uint256 _userBalanceInUsdtReflection = _userBalanceInUsdt.mul(usdtReflection).div(100);
        uint256 _userBalanceInBnbReflection = _userBalanceInBnb.mul(bnbReflection).div(100);
        uint256 _userBalanceInUsdcReflection = _userBalanceInUsdc.mul(usdcReflection).div(100);
        uint256 _userBalanceInEthReflection = _userBalanceInEth.mul(ethReflection).div(100);
        return _userBalanceInUsdtReflection.add(_userBalanceInBnbReflection).add(_userBalanceInUsdcReflection).add(_userBalanceInEthReflection);
    }

