        uint256 _tokenBalance = IERC20(_token).balanceOf(address(this));
        require(_tokenBalance >= _amount, "Insufficient token balance");

        uint256 _tokenAmount = _amount.mul(_feeOnTransfer).div(100);
        uint256 _tokenFee = _amount.mul(_maxFee).div(100);

