function stake(uint256 _amount, uint256 _duration) external {
        require(stakeable, "Staking is not enabled");
        require(msg.sender == owner, "Only owner can stake");
        require(_amount > 0, "Amount must be greater than 0");
        require(_duration > 0, "Duration must be greater than 0");

        uint256 totalStaked = totalStaked();
        uint256 totalStakedDuration = totalStakedDuration();

        uint256 amountToStake = _amount;
        if (totalStakedDuration > 0) {
            amountToStake = _amount.mul(100).div(totalStakedDuration);
        }

        uint256 amountToStakeForDuration = amountToStake.mul(_duration);
        uint256 amountToStakeForTotal = amountToStakeForDuration.mul(100).div(totalStakedDuration);

        uint256 amountToStakeForDurationForTotal = amountToStakeForTotal.mul(100).div(totalStaked);

        uint256 amountToStakeForDurationForTotalForDuration = amountToStakeForDurationForTotal.mul(100).div(totalStakedDuration);

        uint256 amountToStakeForDurationForTotalForDurationForDuration = amountToStakeForDurationForTotalForDuration.mul(100).div(totalStakedDuration);

        uint256 amountToStakeForDurationForTotalForDurationForDurationForDuration = amountToStakeForDurationForTotalForDurationForDuration.mul(100).div(totalStakedDuration);

        uint256 amountToStakeForDurationForTotalForDurationForDurationForDurationForDuration = amountToStakeForDurationForTotalForDurationForDurationForDuration.mul(100).div(totalStakedDuration);

