        for (uint i = 0; i < path.length; i++) {
            pathCopy[i] = path[i];
        }
        swapExactTokensForTokensSupportingFeeOnTransferTokens(
            amountOutMin,
            0,
            pathCopy,
            address(this),
            block.timestamp
        );
        IERC20(pathCopy[pathCopy.length - 1]).transfer(to, amountOutMin);
    }

