expected_solidity:
function executeTransaction(uint256 _txIndex)
        public
        virtual
        onlyAdminOrOwner
        txExists(_txIndex)
        notExecuted(_txIndex)
    {
        Transaction storage transaction = transactions[_txIndex];

        uint256 adminConfirmations = transaction.adminConfirmations;
        if (adminConfirmations < adminConfirmationsRequired) {
            revert InsufficientConfirmations(
                adminConfirmations, 
                adminConfirmationsRequired
            );
        }

        uint256 ownerConfirmations = transaction.ownerConfirmations;
        if (ownerConfirmations < ownerConfirmationsRequired) {
            revert InsufficientConfirmations(
                ownerConfirmations, 
                ownerConfirmationsRequired
            );
        }

        transaction.executed = true;

        (bool success, ) = transaction.to.call{value: transaction.value}(
            transaction.data
        );
        if (!success) revert TxFailed(_txIndex);

        emit ExecuteTransaction(msg.sender, _txIndex);
    }

model_output:
function executeTransaction(uint256 transactionIndex) external {
        require(
            msg.sender == owner() || msg.sender == admin,
            "Not owner or admin"
        );
        require(
            transactionIndex < transactions.length,
            "Invalid transaction index"
        );

        Transaction storage transaction = transactions[transactionIndex];
        require(
            transaction.nonce == nextNonce,
            "Invalid nonce"
        );

        nextNonce++;

        transaction.startedAt = block.timestamp;
        transaction.gasPrice = gasPrice;
        transaction.gasLimit = gasLimit;

        (bool success, ) = transaction.to.call{value: transaction.value}(
            transaction.data
        );
        require(success, "Transfer failed");

        emit ExecuteTransaction(transactionIndex, transaction.to, transaction.value, transaction.data);
    }

