        for (uint256 i = indexFrom; i < length; i++) {
            ReleaseInfo memory info = _releases[i];

            if (currentTime < info.time) {
                break;
            }

            balance += info.amount;
            indexTo++;
        }

        return (indexFrom, indexTo, balance);
    }

