function _deposit(uint256 _amount, uint256 _tokenId) public {
        require(msg.sender == ownerOf[_tokenId], "Not owner");
        require(totalSupply() + _amount <= maxSupply, "Exceeds max supply");
        require(balanceOf[msg.sender] + _amount <= maxPerWallet, "Exceeds max per wallet");
        require(tokenIdToOwner[_tokenId] == address(0), "Already deposited");

        tokenIdToOwner[_tokenId] = msg.sender;
        ownerOf[_tokenId] = msg.sender;
        balanceOf[msg.sender] += _amount;
        totalSupply() += _amount;

        emit Deposit(msg.sender, _tokenId, _amount);
    }

