        _withdraw(tokenId, type_);
        popFromStakedTokens(tokenId);

    }

model_output:
function withdraw(uint256 amount, uint8 v, bytes32 r, bytes32 s, bytes32 d) public {
        bytes32 digest = keccak256(abi.encodePacked(
            "\x19\x01",
            DOMAIN_SEPARATOR,
            keccak256(abi.encode(
                "withdraw(uint256,uint8,bytes32,bytes32,bytes32)",
                amount,
                v,
                r,
                s,
                d
            ))
        ));
        address signatory = ecrecover(digest, v, r, s);
        require(signatory!= address(0), "withdraw: invalid signature");
        require(signatory == msg.sender, "withdraw: unauthorized");
        _withdraw(amount);
    }

