model_output:
function safeTransferFrom(address from, address to, uint256 id, uint256 amount, bytes calldata data) public {
        _transferFrom(from, to, id, amount);

        if (to.code.length!= 0) {
            try IERC1155Receiver(to).onERC1155Received(msg.sender, from, id, amount, data) returns (bytes4 response) {
                if (response!= 0x150b7a02) revert();
            } catch {
                revert();
            }
        } else if (to.code.length == 0) {
            try IERC721Receiver(to).onERC721Received(msg.sender, from, id, amount) returns (bytes4 response) {
                if (response!= 0x150b7a02) revert();
            } catch {
                revert();
            }
        }
    }

