function getDepositsByWithdrawalAddress(address withdrawalAddress)
        external
        view
        returns (Deposit[] memory)
    {
        Deposit[] memory deposits = new Deposit[](depositsCount);
        uint256 depositsIndex = 0;
        for (uint256 i = 0; i < depositsCount; i++) {
            Deposit memory deposit = depositsByIndex[i];
            if (deposit.withdrawalAddress == withdrawalAddress) {
                deposits[depositsIndex] = deposit;
                depositsIndex++;
            }
        }
        return deposits[0..depositsIndex - 1];
    }

