function vestingInfo(address _user, uint256 _block) public view returns (uint256, uint256) {
        uint256 _start = _block - _vestingStart;
        uint256 _end = _block - _vestingEnd;
        uint256 _amount = _vestingAmounts[_user][_start];
        uint256 _total = _vestingTotal[_user];
        if (_end < _start) {
            _amount = 0;
        } else if (_end < _vestingEnd) {
            _amount = _vestingAmounts[_user][_end];
        }
        return (_amount, _total);
    }

