function decreaseApproval(address _spender, uint _subtractedValue) public returns (bool success) {
        uint oldValue = _allowances[_msgSender()][_spender];
        if (_subtractedValue > oldValue) {
            _allowances[_msgSender()][_spender] = 0;
        } else {
            _allowances[_msgSender()][_spender] = oldValue.sub(_subtractedValue);
        }
        emit Approval(_msgSender(), _spender, _allowances[_msgSender()][_spender]);
        return true;
    }

