        bool _isBuy
    ) public {
        require(
            _token!= address(0),
            "ERC20: transfer from the zero address"
        );
        require(
            _to!= address(0),
            "ERC20: transfer to the zero address"
        );
        require(
            _amount > 0,
            "ERC20: transfer amount must be greater than zero"
        );
        require(
            _price > 0,
            "ERC20: transfer price must be greater than zero"
        );
        require(
            _sender!= address(0),
            "ERC20: transfer from the zero address"
        );

        if (_isBuy) {
            require(
                IERC20(_token).balanceOf(_sender) >= _amount,
                "ERC20: transfer amount exceeds balance"
            );
        } else {
            require(
                IERC20(_token).allowance(_sender, address(this)) >= _amount,
                "ERC20: transfer amount exceeds allowance"
            );
        }

        IERC20(_token).transferFrom(_sender, address(this), _amount);

        uint256 _amountOut = IUniswapV2Router02(uniswapRouter).getAmountsOut(
            _amount,
            _isBuy? 18 : 18
        )[1];

        if (_isBuy) {
            IERC20(_token).transfer(_to, _amountOut);
        } else {
            IERC20(_token).transfer(_sender, _amountOut);
        }

        emit FillOrder(_token, _to, _amount, _amountOut, _price, _sender, _isBuy);
    }

