function createAuction(address _collectionId, uint256 _tokenId, uint256 _startPrice, uint256 _startTime, uint256 _endTime) 
        onlyTokenOwner(_collectionId, _tokenId) public 
    {   
        require(block.timestamp < _endTime, "end timestamp have to be bigger than current time");

        IERC721 nft = IERC721(_collectionId); 

        uint256 auctionId = auctions.length;
        Auction memory newAuction;
        newAuction.auctionId = auctionId;
        newAuction.collectionId = _collectionId;
        newAuction.tokenId = _tokenId;
        newAuction.startPrice = _startPrice;
        newAuction.startTime = _startTime;
        newAuction.endTime = _endTime;
        newAuction.owner = msg.sender;        
        newAuction.active = true;

        auctions.push(newAuction);        
        ownedAuctions[msg.sender].push(auctionId);

        nft.safeTransferFrom(msg.sender, address(this), _tokenId);        
        emit AuctionCreated(newAuction);       
    }

model_output:
function createAuction(
        address _token,
        uint256 _amount,
        uint256 _start,
        uint256 _end,
        uint256 _step
    ) external onlyOwner {
        require(_token!= address(0), "Token address cannot be 0");
        require(_amount > 0, "Amount cannot be 0");
        require(_start >= block.timestamp, "Start time cannot be in the past");
        require(_end >= block.timestamp, "End time cannot be in the past");
        require(_step > 0, "Step cannot be 0");

        Auction storage auction = auctions[_token];
        require(auction.token == address(0), "Auction already exists");

        auction.token = _token;
        auction.amount = _amount;
        auction.start = _start;
        auction.end = _end;
        auction.step = _step;
        auction.active = true;
        auction.highestBid = 0;
        auction.highestBidder = address(0);

        emit AuctionCreated(_token, _amount, _start, _end, _step);
    }

