function cancelTrade(uint tradeId) external lock { 
        require(tradeCount >= tradeId && tradeId > 0, "ARK420ERC20P2P_V1: invalid trade id");
        Trade storage trade = trades[tradeId];
        require(trade.initiator == msg.sender, "ARK420ERC20P2P_V1: not allowed");
        require(trade.status == 0 && trade.deadline > block.timestamp, "ARK420ERC20P2P_V1: not active trade");
        trade.status = 2;

        if (trade.proposedAsset != address(ARK420_WETH)) {
            TransferHelper.safeTransfer(trade.proposedAsset, msg.sender, trade.proposedAmount);
        } else {
            ARK420_WETH.withdraw(trade.proposedAmount);
            TransferHelper.safeTransferETH(msg.sender, trade.proposedAmount);
        }

        emit CancelTrade(tradeId);
    }

model_output:
function cancelTrade(uint256 _tradeId) public {
        require(tradeIdToSender[_tradeId] == msg.sender, "You are not the owner of this trade");
        require(tradeIdToStatus[_tradeId] == TradeStatus.Pending, "This trade is not pending");
        require(tradeIdToAmount[_tradeId] > 0, "This trade has not been executed");
        require(tradeIdToAmount[_tradeId] <= tradeIdToAmount[_tradeId], "This trade has been executed");
        tradeIdToStatus[_tradeId] = TradeStatus.Cancelled;
        tradeIdToAmount[_tradeId] = 0;
        tradeIdToSender[_tradeId] = address(0);
        tradeIdToReceiver[_tradeId] = address(0);
        tradeIdToTimestamp[_tradeId] = 0;
        emit TradeCancelled(_tradeId);
    }

