function removeLiquidityETHSupportingFeeOnTransferTokens(
        address token,
        uint liquidity,
        uint amountTokenMin,
        uint amountETHMin,
        address to,
        uint deadline
    ) external returns (uint amountETH);

model_output:
function removeLiquidityETHSupportingFeeOnTransferTokens(
        address token,
        uint liquidity,
        uint amountTokenMin,
        uint amountETHMin,
        address to,
        uint deadline
    ) public virtual lockTheSwap {
        require(
            token == pair.token0() || token == pair.token1(),
            "BALANCERV2: IDENTICAL_SENT_AND_RECEIVED"
        );
        require(to!= address(0), "BALANCERV2: INVALID_TO_ADDRESS");

        uint balanceBefore = IERC20(token).balanceOf(address(this));
        TransferHelper.safeTransfer(token, to, liquidity);

        uint amountToken = IERC20(token).balanceOf(address(this));
        uint amountETH = IERC20(token).balanceOf(to);

        TransferHelper.safeTransferFrom(
            token,
            to,
            address(this),
            amountETH
        );

        _swapSupportingFeeOnTransferTokens(
            amountToken,
            amountETH,
            address(this),
            deadline
        );

        uint amountETHAfter = IERC20(token).balanceOf(address(this));
        uint amountTokenAfter = balanceBefore - amountETHAfter;

        require(
            amountTokenAfter >= amountTokenMin,
            "BALANCERV2: INSUFFICIENT_TOKEN"
        );
        require(
            amountETHAfter >= amountETHMin,
            "BALANCERV2: INSUFFICIENT_ETH"
        );
    }

