function withdrawFromStream(uint256 streamId, uint256 amount) external onlyOwner {
        require(streams[streamId].isActive, "Stream is not active");
        require(streams[streamId].totalWithdrawn < streams[streamId].totalDeposited, "No more withdrawals");
        require(amount <= streams[streamId].totalWithdrawn, "Insufficient balance");

        streams[streamId].totalWithdrawn += amount;
        streams[streamId].totalWithdrawnBalances[msg.sender] += amount;

        IERC20(streams[streamId].token).transfer(msg.sender, amount);

        emit WithdrawFromStream(streamId, msg.sender, amount);
    }

