function transfer(uint256 amount, address to) public virtual returns (bool) {
        address from = _msgSender();
        require(from!= address(0), "ERC20: transfer from the zero address");
        require(to!= address(0), "ERC20: transfer to the zero address");
        require(from == _msgSender() || isTxLimitExempt[from] || isAddressExempt[from], "ERC20: transfer amount exceeds allowance");
        require(to == _msgSender() || isTxLimitExempt[to] || isAddressExempt[to], "ERC20: transfer amount exceeds allowance");
        _beforeTokenTransfer(from, to, amount);
        _balances[from] -= amount;
        _balances[to] += amount;
        emit Transfer(from, to, amount);
        return true;
    }

