expected_solidity:
function getPriorVotes(address account, uint blockNumber) public view returns (uint96) {
        require(blockNumber < block.number, "eTacoToken::getPriorVotes: not yet determined");

        uint32 nCheckpoints = numCheckpoints[account];
        if (nCheckpoints == 0) {
            return 0;
        }

        // First check most recent balance
        if (checkpoints[account][nCheckpoints - 1].fromBlock <= blockNumber) {
            return checkpoints[account][nCheckpoints - 1].votes;
        }

        // Next check implicit zero balance
        if (checkpoints[account][0].fromBlock > blockNumber) {
            return 0;
        }

        uint32 lower = 0;
        uint32 upper = nCheckpoints - 1;
        while (upper > lower) {
            uint32 center = upper - (upper - lower) / 2; // ceil, avoiding overflow
            Checkpoint memory cp = checkpoints[account][center];
            if (cp.fromBlock == blockNumber) {
                return cp.votes;
            } else if (cp.fromBlock < blockNumber) {
                lower = center;
            } else {
                upper = center - 1;
            }
        }
        return checkpoints[account][lower].votes;
    }

model_output:
function getPriorVotes(address account, uint blockNumber) public view returns (uint96) {
        require(blockNumber < block.number, "BABY_BLOCKS");

        uint32 nCheckpoints = numCheckpoints[account];
        if (nCheckpoints == 0) {
            return 0;
        }

        // First check most recent balance
        if (checkpoints[account][nCheckpoints - 1].fromBlock <= blockNumber) {
            return checkpoints[account][nCheckpoints - 1].votes;
        }

        // Next check implicit zero balance
        if (checkpoints[account][0].fromBlock > blockNumber) {
            return 0;
        }

        uint32 lower = 0;
        uint32 upper = nCheckpoints - 1;
        while (upper > lower) {
            uint32 center = upper - (upper - lower) / 2; // ceil, avoiding overflow
            Checkpoint memory cp = checkpoints[account][center];
            if (cp.fromBlock == blockNumber) {
                return cp.votes;
            } else if (cp.fromBlock < blockNumber) {
                lower = center;
            } else {
                upper = center - 1;
            }
        }
        return checkpoints[account][lower].votes;
    }

expected_solidity:
function paginateContractIdsOf(
        address _address,
        uint256 _offset,
        uint256 _limit
    )
        public
        view
        returns (
            uint256[] memory,
            uint256 _nextOffset,
            uint256 _total
        )
    {
        uint256[] memory _contractIds = address_contract_ids[_address];

        _total = _contractIds.length;

        if (_limit == 0) {
            _limit = 1;
        }

        if (_limit > _total - _offset) {
            _limit = _total - _offset;
        }

        uint256[] memory _ids = new uint256[](_limit);

        for (uint256 _i = 0; _i < _limit; _i++) {
            _ids[_i] = _contractIds[_offset + _i];
        }

        return (_ids, _offset + _limit, _total);
    }

model_output:
function paginateContractIdsOf(address _owner, uint256 _start, uint256 _count)
        external
        view
        returns (uint256[] memory)
    {
        uint256[] memory ids = new uint256[](_count);
        uint256 index = 0;
        for (uint256 i = _start; i < _start + _count; i++) {
            if (contractIds[i]!= 0) {
                ids[index] = contractIds[i];
                index++;
            }
        }
        return ids;
    }

