model_output:
function schedule(
        address target,
        uint256 value,
        bytes calldata data,
        bytes32 predecessor,
        bytes32 salt,
        uint256 eta
    ) public payable virtual returns (bytes32) {
        require(msg.value >= value, "EthSender: insufficient funds");

        bytes32 txHash = keccak256(abi.encode(target, value, data, predecessor, salt, eta));
        require(
            _scheduledTransactions[txHash] == address(0),
            "EthSender: transaction already scheduled"
        );

        _scheduledTransactions[txHash] = msg.sender;
        emit Schedule(msg.sender, txHash, target, value, data, predecessor, salt, eta);

        return txHash;
    }

