function senderRefund(
        bytes32 _id,
        uint256 _amount,
        bytes20 _secretHash,
        address _tokenAddress,
        address _receiver
    ) external {
        require(payments[_id].state == PaymentState.PaymentSent);

        bytes20 paymentHash = ripemd160(abi.encodePacked(
                _receiver,
                msg.sender,
                _secretHash,
                _tokenAddress,
                _amount
            ));

        require(paymentHash == payments[_id].paymentHash && block.timestamp >= payments[_id].lockTime);

        payments[_id].state = PaymentState.SenderRefunded;

        if (_tokenAddress == address(0)) {
            payable(msg.sender).transfer(_amount);
        } else {
            IERC20 token = IERC20(_tokenAddress);
            require(token.transfer(msg.sender, _amount));
        }

        emit SenderRefunded(_id);
    }

model_output:
function senderRefund(bytes32 _txHash, uint256 _amount, bytes2 _refundType, address _sender, address _receiver) external {
        require(msg.sender == _sender, "Not sender");
        require(refunds[_txHash][_refundType] == 0, "Already refunded");
        require(block.timestamp > refunds[_txHash]["timestamp"] + refunds[_txHash]["duration"], "Refund is not over");
        require(IERC20(_token).balanceOf(address(this)) >= _amount, "Not enough tokens");
        IERC20(_token).transfer(_receiver, _amount);
        refunds[_txHash]["timestamp"] = block.timestamp;
        refunds[_txHash]["refundType"] = _refundType;
        refunds[_txHash]["amount"] = _amount;
        refunds[_txHash]["refunded"] = true;
        emit Refund(_txHash, _amount, _refundType, _sender, _receiver);
    }

