expected_solidity:
function itoa(uint256 i, uint8 base) public pure returns (string memory a) {
    require(base == 2 || base == 8 || base == 10 || base == 16);
    if (i == 0) {
      return "0";
    }
    bytes memory buf = new bytes(256);
    uint256 p = 0;
    while (i > 0) {
      uint8 digit = uint8(i % base);
      uint8 ascii = digit + 0x30;
      if (digit > 9) {
        ascii += 7;
      }
      buf[p++] = bytes1(ascii);
      i /= base;
    }
    uint256 length = p;
    for (p = 0; p < length / 2; p++) {
      buf[p] ^= buf[length - 1 - p];
      buf[length - 1 - p] ^= buf[p];
      buf[p] ^= buf[length - 1 - p];
    }
    return string(buf);
  }

model_output:
function itoa(uint256 value, uint8 base) public pure returns (string memory) {
        if (value == 0) {
            return "0";
        }
        uint256 temp = value;
        uint256 digits = 0;
        while (temp!= 0) {
            digits++;
            temp /= base;
        }
        bytes memory buffer = new bytes(digits);
        while (value!= 0) {
            uint8 r = (value % base);
            buffer[digits - 1] = r < 10? bytes1(uint8(r + uint8('0'))) : bytes1(uint8(r + uint8('a') - 10));
            value /= base;
            digits--;
        }
        return string(buffer);
    }

