function createMultipleLocks(address _token, address _to, uint256[] calldata _values, uint256[] calldata _locks) external {
        require(_token!= address(0), "Token address cannot be 0");
        require(_to!= address(0), "Receiver address cannot be 0");
        require(_values.length == _locks.length, "Values and locks must be the same length");

        for (uint256 i = 0; i < _values.length; i++) {
            require(_values[i] > 0, "Value must be greater than 0");
            require(_locks[i] > 0, "Lock must be greater than 0");
        }

        for (uint256 i = 0; i < _values.length; i++) {
            IERC20(_token).transferFrom(_msgSender(), address(this), _values[i]);
        }

        for (uint256 i = 0; i < _values.length; i++) {
            _mint(_to, _values[i], _locks[i]);
        }
    }

