expected_solidity:
function arctan(uint256 x) public view returns (uint256) {
        if (x < 2) {
            return 0;
        }

        uint8 bit = log_2(x);
        uint256 base = 1 << bit;
        uint256 db = data[bit];
        uint256 db0 = data[bit - 1];
        return ((db - db0) * (x - base)) / base + db0;
    }

model_output:
function arctan(uint256 _x) public pure returns (uint256) {
        return _x * 180 / PI;
    }

