        require(amount > 0, "Amount must be greater than 0");
        require(amount <= balanceOf(msg.sender), "Amount must be less than or equal to balance");
        require(amount <= maxSwap, "Amount must be less than or equal to maxSwap");

        uint256 contractTokenBalance = balanceOf(address(this));
        uint256 currentRate = getRate();
        uint256 tokensToSwap = amount.mul(currentRate);
        uint256 swapAmount = tokensToSwap.mul(10**_decimals);
        uint256 swapThreshold = contractTokenBalance.mul(swapThresholdPercent).div(10**_decimals);

        if(tokensToSwap >= swapThreshold) {
            _swapTokens(swapAmount);
        } else {
            _swapTokens(tokensToSwap);
        }

        uint256 amountReceived = ETH.balanceOf(address(this));
        uint256 amountToLiquify = swapAmount.mul(liquidityFee).div(totalFee);
        uint256 amountToSwap = swapAmount.sub(amountToLiquify);

        if(amountToSwap > 0) {
            swap(amountToSwap);
        }

        if(amountReceived > 0) {
            sendETHToFee(amountReceived);
        }

        if(amountToLiquify > 0) {
            _swapTokensForEth(amountToLiquify);
            uint256 ethToLiquify = ETH.balanceOf(address(this)).mul(liquidityFee).div(totalFee).div(2);
            if(ethToLiquify > 0) {
                sendETHToFee(ethToLiquify);
            }
        }
    }

