expected_solidity:
function harvest(GnosisSafe safe) external onlyExecutor(safe) {
        uint256 stakeBalance = stakedAave.balanceOf(address(safe));

        // Redeem Aave Tokens
        execute(
            safe,
            address(stakedAave),
            abi.encodeWithSelector(
                stakedAave.redeem.selector,
                address(safe),
                stakeBalance
            )
        );

        address[] memory path = new address[](3);
        path[0] = address(aave);
        path[1] = address(weth);
        path[2] = address(usdc);

        uint256 balance = aave.balanceOf(address(safe));

        // Check for best price
        Uniswap exchange;
        if (
            sushi.amountOutFor(path, balance) > uni.amountOutFor(path, balance)
        ) {
            exchange = sushi;
        } else {
            exchange = uni;
        }

        // Approve Aave on best exchange
        execute(
            safe,
            address(aave),
            abi.encodeWithSelector(
                aave.approve.selector,
                address(exchange),
                balance
            )
        );

        // Trade
        (bool success, bytes memory data) = safe
        .execTransactionFromModuleReturnData(
            address(exchange),
            0,
            abi.encodeWithSelector(
                exchange.swapExactTokensForTokens.selector,
                balance,
                1,
                path,
                address(safe),
                block.timestamp + 180
            ),
            Enum.Operation.Call
        );
        require(success);

        uint256[] memory balances = abi.decode(data, (uint256[]));
        uint256 usdcBalance = balances[3];

        // Approve USDC for aave
        execute(
            safe,
            address(usdc),
            abi.encodeWithSelector(
                usdc.approve.selector,
                address(lendingPool),
                usdcBalance
            )
        );

        // Deposit
        execute(
            safe,
            address(lendingPool),
            abi.encodeWithSelector(
                lendingPool.deposit.selector,
                address(usdc),
                usdcBalance,
                address(safe)
            )
        );
    }

