function pendingLUCARIO( address _user) external view returns (uint256) {
        PoolInfo storage pool = poolInfo[0];
        UserInfo storage user = userInfo[0][_user];
        uint256 accLUCARIOPerShare = pool.accLUCARIOPerShare;

        if (block.number > pool.lastRewardBlock && totalStaked != 0) {
            uint256 multiplier = getMultiplier(pool.lastRewardBlock, block.number);
            uint256 ShowReward = multiplier.mul(LUCARIOPerBlock).mul(pool.allocPoint).div(totalAllocPoint);
            accLUCARIOPerShare = accLUCARIOPerShare.add(ShowReward.mul(1e12).div(totalStaked));
        }
        return user.amount.mul(accLUCARIOPerShare).div(1e12).sub(user.rewardDebt);
    }

