function deposit(uint256 amount, address to) external payable {
        require(msg.value >= amount, "Insufficient funds");
        require(amount > 0, "Amount must be greater than 0");
        require(to!= address(0), "Invalid recipient address");

        // Check if the recipient is whitelisted
        require(isWhitelisted[to], "Recipient is not whitelisted");

        // Check if the recipient has enough balance
        require(balances[to] + amount >= balances[to], "Insufficient balance");

        // Transfer the funds
        balances[to] += amount;
        balances[address(this)] -= amount;

        emit Deposit(msg.sender, to, amount);
    }

