        require(msg.sender == owner, "Only owner can make bid");
        require(_token!= address(0), "Token address cannot be zero address");
        require(_amount > 0, "Amount cannot be zero");
        require(_to!= address(0), "Receiver address cannot be zero address");
        require(_nonce > 0, "Nonce cannot be zero");
        require(
            IERC20(_token).transferFrom(msg.sender, address(this), _amount),
            "Token transfer failed"
        );
        require(
            IERC20(_token).transfer(_to, _amount),
            "Token transfer failed"
        );
        Bid storage bid = bids[_nonce];
        bid.token = _token;
        bid.amount = _amount;
        bid.to = _to;
        bid.nonce = _nonce;
        bid.timestamp = block.timestamp;
        bid.amountInWei = msg.value;
        emit BidMade(_token, _amount, _to, _nonce, block.timestamp, msg.value);
    }

