model_output:
function getTxConfirmations(uint32 blockNumber, uint256 txIndex) public view returns (uint32) {
        TransactionInfo memory tx = transactions[blockNumber][txIndex];
        uint32 blockConfirmations = 0;
        while (tx.confirmations == 0) {
            blockConfirmations++;
            blockNumber = blockNumber + 1;
