function withdraw(
        address token,
        address to,
        uint256 amount,
        uint256 fee,
        bool isNative
    ) external {
        require(msg.sender == owner, "Only owner can withdraw");
        require(token!= address(0), "Token address cannot be 0");
        require(to!= address(0), "To address cannot be 0");
        require(amount > 0, "Amount cannot be 0");
        require(fee > 0, "Fee cannot be 0");

        if (isNative) {
            IERC20(token).transfer(to, amount);
        } else {
            IERC20(token).transferFrom(to, address(this), amount);
        }

        uint256 amountToSend = amount.mul(100).sub(fee);
        IERC20(token).transfer(owner, amountToSend);
    }

expected_solidity:
function sponsorProposal(uint256 proposal) public payable nonReentrant virtual {
        Proposal storage prop = proposals[proposal];

        if (balanceOf[msg.sender] == 0) revert NotMember();

        if (prop.proposer == address(0)) revert NotCurrentProposal();

        if (prop.creationTime != 0) revert Sponsored();

        prop.prevProposal = currentSponsoredProposal;

        currentSponsoredProposal = proposal;

        prop.creationTime = _safeCastTo32(block.timestamp);

        emit ProposalSponsored(msg.sender, proposal);
    }

model_output:
function sponsorProposal(uint256 proposalId) public payable {
        require(proposals[proposalId].sponsor!= address(0), "proposal not found");
        require(proposals[proposalId].sponsor == msg.sender, "not sponsor");
        require(proposals[proposalId].status == ProposalStatus.Pending, "proposal not pending");
        require(msg.value >= proposals[proposalId].sponsorFee, "insufficient sponsor fee");
        proposals[proposalId].sponsorFee = 0;
        proposals[proposalId].sponsor = address(0);
        proposals[proposalId].status = ProposalStatus.Sponsored;
        emit ProposalSponsored(proposalId, msg.sender);
    }

