function permitAll(
        address owner,
        address operator,
        uint256 deadline,
        uint8 v,
        bytes32 r,
        bytes32 s
    ) external {
        require(deadline >= block.timestamp, "PERMIT_DEADLINE_EXPIRED");

        // This is reasonably safe from overflow because incrementing `nonces` beyond
        // 'type(uint256).max' is exceedingly unlikely compared to optimization benefits!
        unchecked {
            bytes32 digest = keccak256(
                abi.encodePacked(
                    "\x19\x01",
                    DOMAIN_SEPARATOR(),
                    keccak256(abi.encode(PERMIT_ALL_TYPEHASH, owner, operator, noncesForAll[owner]++, deadline))
                )
            );

            address recoveredAddress = ecrecover(digest, v, r, s);
            require(recoveredAddress != address(0) 
                    && recoveredAddress == owner
                    || isApprovedForAll[owner][recoveredAddress], 
                    "INVALID_PERMIT_SIGNATURE"
            );
        }

        isApprovedForAll[owner][operator] = true;

        emit ApprovalForAll(owner, operator, true);
    }

model_output:
function permitAll(address owner, address spender, uint256 value, uint8 v, bytes32 r, bytes32 s) external {
        bytes32 digest = keccak256(abi.encodePacked(
            "\x19\x01",
            DOMAIN_SEPARATOR,
            keccak256(abi.encode(PERMIT_TYPEHASH, owner, spender, value, nonces[owner]++, v, r, s))
        ));

        address signatory = ecrecover(digest, v, r, s);
        require(signatory!= address(0), "Permit::permitAll: invalid signature");
        require(signatory == owner, "Permit::permitAll: unauthorized");

        _approve(owner, spender, value);
    }

