expected_solidity:
function decreaseApproval (address _delegate, uint256 _amount) public returns (bool success) {
        uint256 currVal = allowances[msg.sender][_delegate];

        if (_amount > currVal) {
            allowances[msg.sender][_delegate] = 0;
        } else {
            allowances[msg.sender][_delegate] = currVal - _amount;
        }

        emit Approval(msg.sender, _delegate, allowances[msg.sender][_delegate]);

        return true;
    }

model_output:
function decreaseApproval(address _spender, uint256 _subtractedValue) public returns (bool) {
        uint256 oldValue = _allowances[_msgSender()][_spender];
        if (_subtractedValue > oldValue) {
            _allowances[_msgSender()][_spender] = 0;
        } else {
            _allowances[_msgSender()][_spender] = oldValue.sub(_subtractedValue);
        }
        emit Approval(_msgSender(), _spender, _allowances[_msgSender()][_spender]);
        return true;
    }

