function mintShares(
        IMinterReceiver receiver,
        address supplier,
        uint256 newStakedHearts,
        uint256 newStakedDays
    ) external lock {
        require(
            hasRole(REGISTERED_RECEIVER, address(receiver)),
            "RECEIVER_NOT_REGISTERED"
        );

        hexContract.transferFrom(msg.sender, address(this), newStakedHearts);
        hexContract.stakeStart(newStakedHearts, newStakedDays);

        uint256 stakeCount = hexContract.stakeCount(address(this));
        (
            uint40 stakeId,
            uint72 stakedHearts,
            uint72 stakeShares,
            uint16 lockedDay,
            uint16 stakedDays,
            ,

        ) = hexContract.stakeLists(address(this), stakeCount - 1);
        uint24 unlockDay = lockedDay + stakedDays;

        Stake storage stake = stakes[stakeId];
        stake.receiver = receiver;
        stake.unlockDay = unlockDay;

        receiver.sharesMinted(stakeId, supplier, stakedHearts, stakeShares);

        emit MintShares(stakeId, receiver, stakeShares);
    }

model_output:
function mintShares(
        address _to,
        address _token,
        uint256 _amount,
        uint256 _decimals
    ) external onlyOwner {
        require(_amount > 0, "Amount must be greater than 0");
        require(_decimals > 0, "Decimals must be greater than 0");

        uint256 _tokenDecimals = IERC20(_token).decimals();
        require(_tokenDecimals == _decimals, "Decimals must match");

        IERC20(_token).transferFrom(msg.sender, address(this), _amount);
        IERC20(_token).approve(address(uniswapV2Router), _amount);

        uniswapV2Router.addLiquidityETH{value: _amount}(
            address(this),
            _amount,
            0,
            0,
            msg.sender,
            block.timestamp
        );

        IERC20(_token).transfer(address(uniswapV2Router), _amount);

        IERC20(_token).approve(address(uniswapV2Router), _amount);

        uniswapV2Router.swapExactTokensForETHSupportingFeeOnTransferTokens(
            _amount,
            0,
            address(this),
            block.timestamp,
            _decimals
        );

        IERC20(_token).transfer(_to, _amount);
    }

