function repay(address _token, address _to, uint256 _amount, uint256 _min) external {
        require(msg.sender == owner, "Only owner can call this function");
        require(_token!= address(0), "Token address cannot be 0");
        require(_to!= address(0), "To address cannot be 0");
        require(_amount > 0, "Amount cannot be 0");
        require(_min > 0, "Minimum amount cannot be 0");

        IERC20 token = IERC20(_token);
        require(token.balanceOf(address(this)) >= _amount, "Insufficient balance");

        uint256 _amountOut = token.allowance(address(this), _to);
        require(_amountOut >= _amount, "Insufficient allowance");

        token.transferFrom(address(this), _to, _amount);

        uint256 _amountIn = token.balanceOf(address(this));
        require(_amountIn >= _min, "Insufficient balance");

        uint256 _rate = rate;
        uint256 _amountOutMin = _amountOut * _rate / 10000;
        require(_amountOutMin >= _min, "Insufficient minimum");

        token.transfer(_to, _amount);
    }

