function claim(uint32 _round) external {
        require(rounds[_round].status == RoundStatus.Pending, "Round not pending");
        require(rounds[_round].startTime + rounds[_round].duration > block.timestamp, "Round not finished");
        require(rounds[_round].amount > 0, "Round has no amount");
        require(rounds[_round].amount <= rounds[_round].amountClaimed, "Round has already been claimed");

        rounds[_round].amountClaimed++;
        rounds[_round].amountClaimedBy[msg.sender] = true;

        IERC20(token).transfer(msg.sender, rounds[_round].amount);

        emit Claim(msg.sender, _round, rounds[_round].amount);
    }

