model_output:
function bet(uint256 _amount, uint8 _odds) external payable {
        require(msg.value >= _amount, "Insufficient funds");
        require(odds[_odds] > 0, "Invalid odds");
        require(odds[_odds] <= _amount, "Insufficient funds");

        uint256 amount = _amount * odds[_odds] / 10000;
        uint256 fee = _amount * 1 / 10000;

