        require(stake.stakeTime + stake.stakeDuration > block.timestamp, "Stake is not expired");
        require(stake.stakeStatus == StakeStatus.Staked, "Stake is not staked");
        stake.stakeStatus = StakeStatus.UnStaked;
        stake.unStakeTime = block.timestamp;
        stake.unStakeAmount = stake.stakeAmount;
        stake.stakeAmount = 0;
        emit UnStake(msg.sender, _stakeId, stake.unStakeAmount);
    }

