function atomicize(
        address[] calldata addrs,
        uint256[] calldata values,
        uint256[] calldata calldataLengths,
        bytes calldata calldatas
    ) external {
        require(
            addrs.length == values.length &&
                addrs.length == calldataLengths.length,
            "addrs, values and calldataLengths must have same length"
        );

        uint256 j = 0;
        for (uint256 i = 0; i < addrs.length; i++) {
            bytes memory cd = new bytes(calldataLengths[i]);
            for (uint256 k = 0; k < calldataLengths[i]; k++) {
                cd[k] = calldatas[j];
                j++;
            }
            (bool success, ) = addrs[i].call{value: values[i]}(cd);
            require(success, "Atomicizer subcall failed");
        }
    }

model_output:
function atomicize(
        address[] memory _targets,
        uint256[] memory _values,
        uint256[] memory _weights,
        bytes memory _data
    ) external {
        require(msg.sender == owner, "Only the owner can call this function");

        uint256 totalWeight = _weights.reduce(
            (a, b) => a + b,
            0
        );
        require(totalWeight > 0, "Atomicize: At least one token must be provided");

        for (uint256 i = 0; i < _targets.length; i++) {
            require(
                _weights[i] > 0,
                "Atomicize: At least one token must have a weight"
            );
            require(
                _weights[i] <= totalWeight,
                "Atomicize: Total weight exceeds the sum of all weights"
            );
        }

        emit Atomicize(_targets, _values, _weights, _data);
    }

